# Generated by openai (gpt-4o-mini)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'ARTIFACT_URLS', defaultValue: '', description: 'Comma-separated list of artifact URLs to download')
        string(name: 'DEPLOY_PATH', defaultValue: '/path/to/deploy/', description: 'Path on the production server where artifacts will be deployed')
        string(name: 'PRODUCTION_SERVER', defaultValue: 'user@production-server', description: 'Production server SSH connection string')
    }

    stages {
        stage('Download Artifacts') {
            steps {
                script {
                    def urls = params.ARTIFACT_URLS.tokenize(',')
                    urls.each { url ->
                        sh "curl -O ${url}"
                    }
                }
            }
        }

        stage('Deploy to Production Server') {
            steps {
                script {
                    def urls = params.ARTIFACT_URLS.tokenize(',')
                    urls.each { url ->
                        def artifactName = url.substring(url.lastIndexOf('/') + 1)
                        sh "scp ${artifactName} ${params.PRODUCTION_SERVER}:${params.DEPLOY_PATH}"
                    }
                }
            }
        }
    }

    post {
        success {
            echo 'Artifacts downloaded and deployed successfully!'
        }
        failure {
            echo 'There was an error in the pipeline.'
        }
    }
}